using System;
using System.IO;
using System.Runtime.Serialization.Formatters.Binary;

public class SessionManager
{
    private const string SESSION_FILE = "session.dat";

    public void SaveSession(UserSession session)
    {
        using (var stream = new FileStream(SESSION_FILE, FileMode.Create))
        {
            var formatter = new BinaryFormatter();
            formatter.Serialize(stream, session);
        }
    }

    public UserSession LoadSession()
    {
        if (!File.Exists(SESSION_FILE))
        {
            return null;
        }

        using (var stream = new FileStream(SESSION_FILE, FileMode.Open))
        {
            var formatter = new BinaryFormatter();
            return (UserSession)formatter.Deserialize(stream);
        }
    }
}

